// VIKS Animation Library
class ViksAnimation {
    constructor(options = {}) {
        this.options = {
            offset: options.offset || 120,
            delay: options.delay || 0,
            duration: options.duration || 400,
            easing: options.easing || 'ease',
            once: options.once || false,
            mirror: options.mirror || false,
            anchorPlacement: options.anchorPlacement || 'top-bottom',
            threshold: options.threshold || 0.2,
        };

        this.animatedElements = new Set();
        this.observer = null;
        this.init();
    }

    init() {
        // Create Intersection Observer
        this.observer = new IntersectionObserver(
            (entries) => {
                entries.forEach((entry) => {
                    if (entry.isIntersecting) {
                        this.animate(entry.target, true);
                    } else if (this.options.mirror) {
                        this.animate(entry.target, false);
                    }
                });
            },
            {
                threshold: this.options.threshold,
                rootMargin: `${-this.options.offset}px 0px`,
            }
        );

        // Initialize elements
        this.refresh();

        // Add scroll event listener for parallax effects
        window.addEventListener('scroll', () => this.handleScroll(), { passive: true });
    }

    animate(element, isInView) {
        const animationName = element.getAttribute('data-viks');
        if (!animationName) return;

        const delay = element.getAttribute('data-viks-delay') || this.options.delay;
        const duration = element.getAttribute('data-viks-duration') || this.options.duration;
        const easing = element.getAttribute('data-viks-easing') || this.options.easing;

        element.style.animationDelay = `${delay}ms`;
        element.style.animationDuration = `${duration}ms`;
        element.style.animationTimingFunction = easing;

        if (isInView) {
            element.classList.add('viks-animated', animationName);
            element.style.visibility = 'visible';

            if (this.options.once) {
                this.observer.unobserve(element);
            }

            // Trigger callback if defined
            const callback = element.getAttribute('data-viks-callback');
            if (callback && window[callback]) {
                window[callback](element);
            }
        } else {
            element.classList.remove('viks-animated', animationName);
            if (!this.options.once) {
                element.style.visibility = 'hidden';
            }
        }
    }

    refresh() {
        document.querySelectorAll('[data-viks]').forEach(element => {
            if (!this.animatedElements.has(element)) {
                this.animatedElements.add(element);
                element.style.visibility = 'hidden';
                this.observer.observe(element);
            }
        });
    }

    handleScroll() {
        requestAnimationFrame(() => {
            this.animatedElements.forEach(element => {
                if (this.isElementInViewport(element)) {
                    const scrollProgress = this.calculateScrollProgress(element);
                    
                    // Handle parallax effects
                    if (element.hasAttribute('data-viks-parallax')) {
                        const speed = parseFloat(element.getAttribute('data-viks-parallax')) || 0.5;
                        const translateY = scrollProgress * speed;
                        element.style.transform = `translateY(${translateY}px)`;
                    }
                }
            });
        });
    }

    isElementInViewport(element) {
        const rect = element.getBoundingClientRect();
        return (
            rect.top <= (window.innerHeight || document.documentElement.clientHeight) &&
            rect.bottom >= 0
        );
    }

    calculateScrollProgress(element) {
        const rect = element.getBoundingClientRect();
        const windowHeight = window.innerHeight || document.documentElement.clientHeight;
        return (windowHeight - rect.top) / (windowHeight + rect.height);
    }
}

// Global initialization
window.viks = new ViksAnimation({
    offset: 120,
    delay: 0,
    duration: 400,
    easing: 'ease',
    once: false,
    mirror: true,
    anchorPlacement: 'top-bottom',
    threshold: 0.2
});

// Reinitialize on dynamic content changes
document.addEventListener('DOMContentLoaded', () => window.viks.refresh());